import shioaji as _sj

_EXPORTS = {
    "ReserveStockSummary": "ReserveStockSummary",
    "ReserveStocksSummary": "ReserveStocksSummary",
    "ReserveStockDetail": "ReserveStockDetail",
    "ReserveStocksDetail": "ReserveStocksDetail",
    "EarmarkStockDetail": "EarmarkStockDetail",
    "EarmarkStocksDetail": "EarmarkStocksDetail",
    "ReserveOrderResp": "ReserveOrderResp",
    "EarmarkingOrderResp": "EarmarkingOrderResp",
    "ReserveStocksSummaryResponse": "ReserveStocksSummaryResponse",
    "ReserveStocksDetailResponse": "ReserveStocksDetailResponse",
    "ReserveStockResponse": "ReserveStockResponse",
    "EarmarkStocksDetailResponse": "EarmarkStocksDetailResponse",
    "ReserveEarmarkingResponse": "ReserveEarmarkingResponse",
}

def __getattr__(name):
    if name in _EXPORTS:
        import warnings
        warnings.warn(
            f"shioaji.reserve.{name} is deprecated, use sj.{_EXPORTS[name]}",
            DeprecationWarning,
            stacklevel=2,
        )
        return getattr(_sj, _EXPORTS[name])
    raise AttributeError(f"module 'shioaji.reserve' has no attribute {name!r}")
